1	// Seed runner.
2	// Idempotent — safe to re-run.
3	//
4	// Seeds:
5	//   * settings table — defaults from spec 6.2
6	//   * employees       — single admin row per user decision #3
7	//                       + a single test-only employee for Phase 2 acceptance
8	//                         (see DECISIONS.md D1.test-employee — delete before production)
9	
10	import { config as loadEnv } from 'dotenv';
11	import { dirname, resolve } from 'node:path';
12	import { fileURLToPath, pathToFileURL } from 'node:url';
13	import postgres from 'postgres';
14	import { drizzle } from 'drizzle-orm/postgres-js';
15	import { sql } from 'drizzle-orm';
16	import * as schema from './schema';
17	import { settings, employees } from './schema';
18	
19	const __dirname = dirname(fileURLToPath(import.meta.url));
20	const repoRoot = resolve(__dirname, '..', '..', '..');
21	// Load .env.local first (takes precedence), then .env as fallback.
22	loadEnv({ path: resolve(repoRoot, '.env.local') });
23	loadEnv({ path: resolve(repoRoot, '.env') });
