25	const DEFAULT_SETTINGS: Array<{
26	  key: string;
27	  value: unknown;
28	  description: string;
29	}> = [
30	  { key: 'lull_window_seconds', value: 60, description: 'Seconds of human silence before Oracle may interject (spec 5.1).' },
31	  { key: 'oracle_cooldown_minutes', value: 10, description: 'Minimum minutes between Oracle interjections in a single channel.' },
32	  { key: 'max_oracle_interjections_per_hour', value: 3, description: 'Per-channel cap on proactive interjections.' },
33	  // Legacy OpenRouter model id keys — kept during R1 migration, do not use for new code.
34	  // See docs/oracle/05-ai-retrofit-phase-packet.md Phase R1 task 8.
35	  { key: 'default_interview_model', value: 'deepseek/deepseek-v4-pro', description: 'DEPRECATED — Legacy OpenRouter model id. Superseded by default_interview_route.' },
36	  { key: 'default_extraction_model', value: 'google/gemini-2.5-flash', description: 'DEPRECATED — Legacy OpenRouter model id. Superseded by default_extraction_route.' },
37	  { key: 'default_synthesis_model', value: 'anthropic/claude-sonnet-4.6', description: 'DEPRECATED — Legacy OpenRouter model id. Superseded by default_synthesis_route.' },
38	  // R1 — Curated Oracle route IDs (Big 3 provider-native). 1 Primary per role.
39	  // Source of truth: packages/ai/src/routes/defaults.ts (DEFAULT_ORACLE_ROUTES).
40	  { key: 'default_interview_route', value: 'anthropic_claude_haiku_4_5_interview_primary', description: 'Curated OracleModelRoute.routeId for the interview role.' },
41	  { key: 'default_extraction_route', value: 'vertex_gemini_2_5_flash_extraction_primary', description: 'Curated OracleModelRoute.routeId for the extraction role.' },
42	  { key: 'default_synthesis_route', value: 'anthropic_claude_3_5_sonnet_synthesis_primary', description: 'Curated OracleModelRoute.routeId for the synthesis role.' },
43	  { key: 'enable_live_contradiction_interjections', value: false, description: 'When false, possible contradictions queue silently (spec 5.1 Rule 1).' },
44	  { key: 'enable_group_chat_lull_questions', value: true, description: 'When true, Oracle may ask a high-priority gap question during a lull (spec 5.1 Rule 2).' },
45	  // D14 — provider Batch API dispatch mode for claim extraction.
46	  // 'sync' (default) runs the existing per-segment pipeline against the
47	  // sync model API. 'batch' submits all segments via the provider Batch API
48	  // (~50% off, 24-hour SLA) and the drain task processes results when ready.
49	  // The sync worker bails when set to 'batch'; the batch-submit worker bails
50	  // when set to 'sync'. Flag is read every run — flip without redeploying.
51	  { key: 'extraction_dispatch_mode', value: 'sync', description: 'sync | batch — D14 provider Batch API dispatch for claim extraction.' },
52	];
