54	const ADMIN_EMPLOYEE = {
55	  email: 'u2giants@gmail.com',
56	  name: 'Albert H.',
57	  role: 'Lead Architect',
58	  department: 'Executive',         // legacy field — kept for backward compat
59	  departments: ['Executive'],
60	  isAdmin: true,
61	};
62	
63	const TEST_EMPLOYEE = {
64	  // See DECISIONS.md D1.test-employee — Phase 2 acceptance gate needs 2 employees
65	  // to verify cross-channel RLS. Delete this row before production rollout.
66	  email: 'test-employee@oracle.local',
67	  name: 'Test Employee',
68	  role: 'Production Coordinator',
69	  department: 'Production',        // legacy field
70	  departments: ['Production'],
