74	export async function runSeed(existingClient?: ReturnType<typeof postgres>): Promise<void> {
75	  const ownsClient = !existingClient;
76	  const client =
77	    existingClient ??
78	    postgres(process.env.DIRECT_URL ?? process.env.DATABASE_URL ?? '', {
79	      max: 1,
80	      prepare: true,
81	    });
82	
83	  try {
84	    const db = drizzle(client, { schema });
85	
86	    // Settings — upsert each row by key.
87	    for (const s of DEFAULT_SETTINGS) {
88	      await db
89	        .insert(settings)
90	        .values({ key: s.key, value: s.value as never, description: s.description })
91	        .onConflictDoUpdate({
92	          target: settings.key,
93	          set: { value: s.value as never, description: s.description, updatedAt: new Date() },
94	        });
95	    }
96	
97	    // Admin employee — upsert by email.
98	    await db
99	      .insert(employees)
100	      .values({
101	        email: ADMIN_EMPLOYEE.email,
102	        name: ADMIN_EMPLOYEE.name,
103	        role: ADMIN_EMPLOYEE.role,
104	        department: ADMIN_EMPLOYEE.department,
105	        departments: ADMIN_EMPLOYEE.departments,
106	        isAdmin: ADMIN_EMPLOYEE.isAdmin,
107	      })
108	      .onConflictDoUpdate({
109	        target: employees.email,
110	        set: {
111	          name: ADMIN_EMPLOYEE.name,
112	          role: ADMIN_EMPLOYEE.role,
113	          department: ADMIN_EMPLOYEE.department,
114	          departments: ADMIN_EMPLOYEE.departments,
115	          isAdmin: ADMIN_EMPLOYEE.isAdmin,
116	        },
117	      });
118	
119	    // Test employee — for Phase 2 acceptance.
120	    await db
121	      .insert(employees)
122	      .values({
123	        email: TEST_EMPLOYEE.email,
124	        name: TEST_EMPLOYEE.name,
125	        role: TEST_EMPLOYEE.role,
126	        department: TEST_EMPLOYEE.department,
127	        departments: TEST_EMPLOYEE.departments,
128	        isAdmin: TEST_EMPLOYEE.isAdmin,
129	      })
130	      .onConflictDoNothing({ target: employees.email });
131	
132	    // Sanity assertion — make sure RLS got enabled on critical tables.
133	    const rlsCheck = await db.execute(sql`
134	      SELECT relname, relrowsecurity
135	      FROM pg_class
136	      WHERE relname IN ('employees', 'messages', 'channels', 'claims')
137	      ORDER BY relname;
138	    `);
139	    console.log('  RLS status:', rlsCheck);
140	  } finally {
141	    if (ownsClient) await client.end({ timeout: 5 });
142	  }
143	}
