146	// Use pathToFileURL for a robust cross-platform check (handles Windows triple-slash file URLs).
147	const entryUrl = process.argv[1] ? pathToFileURL(process.argv[1]).href : '';
148	const isDirect = import.meta.url === entryUrl;
149	if (isDirect) {
150	  runSeed().catch((err) => {

1	/**
2	 * R5.5 — Canonical entity resolver.
3	 *
4	 * Resolves a model-proposed entity reference against the canonical
5	 * `entities` registry. Pure function: takes the proposal + the registry
6	 * subset the caller fetched, returns one of four outcomes.
7	 *
8	 * Critically: this resolver REFUSES to silently accept a licensor-named
9	 * entity proposed under `entity_type = 'vendor'`. That structural
10	 * enforcement is the new docs/oracle/07-knowledge-segmentation.md rule
11	 * ("licensor is a first-class type distinct from vendor"). The registry
12	 * is the source of truth — if the proposal's name resolves under a
13	 * different `entity_type`, the resolver returns `type_mismatch` so the
14	 * candidate is held instead of writing the wrong row.
15	 *
16	 * Per docs/oracle/05-ai-retrofit-phase-packet.md Phase R5.5.
17	 */
18	
19	import type { EntityType } from '@oracle/shared';
20	import { canonicalizeSummary } from './candidate-hash';
21	
22	// ─────────────────────────────────────────────────────────────────────────
23	// Registry shape
24	// ─────────────────────────────────────────────────────────────────────────
25	
26	/**
27	 * Registry row the caller fetched from `entities`. Only the fields the
28	 * resolver needs are required; callers can include more.
29	 */
30	export interface RegistryEntity {
31	  id: string;
32	  entityType: EntityType;
33	  canonicalValue: string;
34	  /** Optional aliases array. Treated case-insensitively + whitespace-collapsed. */
35	  aliases?: string[] | null;
36	}
37	
38	// ─────────────────────────────────────────────────────────────────────────
39	// Inputs and outputs
40	// ─────────────────────────────────────────────────────────────────────────
41	
42	export interface ResolveEntityInput {
43	  /** The entity type the model proposed for this reference. */
44	  proposedEntityType: EntityType;
45	  /** The raw string the model surfaced (could be canonical or an alias). */
46	  rawString: string;
47	  /**
48	   * The subset of the registry the caller fetched. The caller decides how
49	   * to scope this — for performance it's typically the union of:
50	   *   1. all entities matching `entity_type = proposedEntityType`
51	   *   2. plus any entities whose canonical_value matches `rawString` case-
52	   *      insensitively across ANY type (so type-mismatch detection works)
53	   */
54	  registry: RegistryEntity[];
55	}
56	
57	export type ResolveEntityResult =
58	  | {
59	      outcome: 'resolved';
60	      entityId: string;
61	      entityType: EntityType;
62	      canonicalValue: string;
63	      matchKind: 'canonical_exact' | 'alias';
64	    }
65	  | {
66	      outcome: 'unknown';
67	      /** No registry entry matched — caller should stage an entity_proposals row. */
68	      proposal: {
69	        proposedEntityType: EntityType;
70	        proposedCanonicalValue: string;
71	        rawString: string;
72	      };
73	    }
74	  | {
75	      outcome: 'type_mismatch';
76	      /**
77	       * The name resolves in the registry but under a different
78	       * entity_type. This catches "Disney as vendor" type errors —
79	       * Disney is a `licensor`, not a `vendor`. The candidate is held
80	       * until an admin reviews.
81	       */
82	      matchedEntityId: string;
83	      matchedEntityType: EntityType;
84	      matchedCanonicalValue: string;
85	      proposedEntityType: EntityType;
86	      rawString: string;
87	    }
88	  | {
89	      outcome: 'ambiguous';
90	      /** Multiple registry entries match the alias under the same type. */
91	      candidates: Array<{ entityId: string; canonicalValue: string }>;
92	      proposedEntityType: EntityType;
93	      rawString: string;
94	    };
95	
96	// ─────────────────────────────────────────────────────────────────────────
97	// Resolver
98	// ─────────────────────────────────────────────────────────────────────────
99	
100	/**
101	 * Resolve a single entity reference. See the ResolveEntityResult shape
102	 * for the full set of outcomes.
103	 */
104	export function resolveEntity(input: ResolveEntityInput): ResolveEntityResult {
105	  const { proposedEntityType, rawString, registry } = input;
106	  const normalizedRaw = canonicalizeSummary(rawString);
107	
108	  // ── 1. Match within the proposed type by canonical value, then aliases.
109	  const sameType = registry.filter((e) => e.entityType === proposedEntityType);
110	  const canonicalExact = sameType.filter(
111	    (e) => canonicalizeSummary(e.canonicalValue) === normalizedRaw,
112	  );
113	
114	  if (canonicalExact.length === 1) {
115	    return {
116	      outcome: 'resolved',
117	      entityId: canonicalExact[0]!.id,
118	      entityType: canonicalExact[0]!.entityType,
119	      canonicalValue: canonicalExact[0]!.canonicalValue,
120	      matchKind: 'canonical_exact',
121	    };
122	  }
123	  if (canonicalExact.length > 1) {
124	    return {
125	      outcome: 'ambiguous',
126	      candidates: canonicalExact.map((e) => ({ entityId: e.id, canonicalValue: e.canonicalValue })),
127	      proposedEntityType,
128	      rawString,
129	    };
130	  }
131	
132	  const aliasMatches = sameType.filter((e) =>
133	    (e.aliases ?? []).some((a) => canonicalizeSummary(a) === normalizedRaw),
134	  );
135	  if (aliasMatches.length === 1) {
136	    return {
137	      outcome: 'resolved',
138	      entityId: aliasMatches[0]!.id,
139	      entityType: aliasMatches[0]!.entityType,
140	      canonicalValue: aliasMatches[0]!.canonicalValue,
141	      matchKind: 'alias',
142	    };
143	  }
144	  if (aliasMatches.length > 1) {
145	    return {
146	      outcome: 'ambiguous',
147	      candidates: aliasMatches.map((e) => ({ entityId: e.id, canonicalValue: e.canonicalValue })),
148	      proposedEntityType,
149	      rawString,
150	    };
151	  }
152	
153	  // ── 2. Cross-type lookup: did the model put Disney under `vendor`?
154	  // We search across ALL types for a canonical or alias match. If we find
155	  // one under a different type, we surface a `type_mismatch` rather than
156	  // silently creating a new entity_proposals row.
157	  for (const e of registry) {
158	    if (e.entityType === proposedEntityType) continue;
159	    if (canonicalizeSummary(e.canonicalValue) === normalizedRaw) {
160	      return {
161	        outcome: 'type_mismatch',
162	        matchedEntityId: e.id,
163	        matchedEntityType: e.entityType,
164	        matchedCanonicalValue: e.canonicalValue,
165	        proposedEntityType,
166	        rawString,
167	      };
168	    }
169	    if ((e.aliases ?? []).some((a) => canonicalizeSummary(a) === normalizedRaw)) {
170	      return {
171	        outcome: 'type_mismatch',
172	        matchedEntityId: e.id,
173	        matchedEntityType: e.entityType,
174	        matchedCanonicalValue: e.canonicalValue,
175	        proposedEntityType,
176	        rawString,
177	      };
178	    }
179	  }
180	
181	  // ── 3. Nothing matched. Stage as an entity_proposals row. The proposed
182	  // canonical value defaults to the raw string trimmed; admin review can
183	  // rename it during approval.
184	  return {
185	    outcome: 'unknown',
186	    proposal: {
187	      proposedEntityType,
188	      proposedCanonicalValue: rawString.trim(),
189	      rawString,
190	    },
191	  };
192	}
