9	//    claim_evidence unchanged."
10	//
11	// And docs/oracle/07-knowledge-segmentation.md governance rules:
12	//   - No auto-mutation. Only an admin approval triggers the mutation.
13	//   - approved/rejected proposals MUST record the reviewer + timestamp
14	//     (taxonomy_proposals_reviewed_consistency_check enforces this).
15	//   - Every accepted change writes a taxonomy_change_log audit row.
16	
17	import { revalidatePath } from 'next/cache';
18	import { and, eq, isNull } from 'drizzle-orm';
19	import {
20	  entityProposals,
21	  entities,
22	  knowledgeTopDomains,
23	  taxonomyChangeLog,
