182	  const entityProposalsToStage = taxonomy?.entityProposalsToCreate ?? [];
183	
184	  // Idempotency: re-running the promoter on an already-promoted candidate
185	  // returns 'already_promoted' without trying to insert anything.
186	  if (candidate.status === 'promoted') {
187	    return {
188	      kind: 'reject',
189	      reason: 'already_promoted',
190	      detail: `Candidate ${candidate.id} is already promoted to claim ${candidate.promotedToClaimId ?? '<unknown>'}.`,
191	      entityProposalsToStage,
192	    };
193	  }
194	
195	  // The candidate must be 'validated' before promotion. Anything else
196	  // (pending_validation, validation_failed, rejected, *_sensitive) gets
197	  // rejected here — the only way out of those states is review, not promotion.
198	  if (candidate.status !== 'validated') {
199	    return {
200	      kind: 'reject',
